import React, { useState, useEffect, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
  },
  font: "'JetBrains Mono', monospace",
};

const ALPHA = 0.9, BETA = 3, GAMMA = 0.5;
const REFERENCE = 'The cat sat on the mat';
const chunkColors = ['#38bdf8', '#f472b6', '#fbbf24', '#a3e635', '#fb923c', '#c084fc', '#f87171', '#34d399'];

const presets = [
  { label: 'Perfect', text: 'The cat sat on the mat' },
  { label: 'Scrambled', text: 'On the mat sat the cat' },
  { label: 'Partial', text: 'A cat sat on a mat' },
  { label: 'Synonyms', text: 'The kitten rested on the rug' },
  { label: 'Poor', text: 'A dog ran through the park' },
];

function computeMeteor(reference, candidate) {
  const refTokens = reference.toLowerCase().split(/\s+/).filter(Boolean);
  const candTokens = candidate.toLowerCase().split(/\s+/).filter(Boolean);
  if (refTokens.length === 0 || candTokens.length === 0) {
    return { refTokens, candTokens, numMatches: 0, precision: 0, recall: 0, fmean: 0, numChunks: 0, penalty: 0, score: 0, matchPairs: [], chunkIds: [], matchedPositions: [] };
  }
  const refCounts = {};
  refTokens.forEach(t => refCounts[t] = (refCounts[t] || 0) + 1);
  const candCounts = {};
  candTokens.forEach(t => candCounts[t] = (candCounts[t] || 0) + 1);
  let numMatches = 0;
  for (const word in candCounts) {
    if (refCounts[word]) numMatches += Math.min(candCounts[word], refCounts[word]);
  }
  const precision = numMatches / candTokens.length;
  const recall = numMatches / refTokens.length;
  if (numMatches === 0) {
    return { refTokens, candTokens, numMatches: 0, precision: 0, recall: 0, fmean: 0, numChunks: 0, penalty: 0, score: 0, matchPairs: [], chunkIds: [], matchedPositions: [] };
  }
  const fmean = (precision * recall) / (ALPHA * precision + (1 - ALPHA) * recall);
  const refPositions = {};
  refTokens.forEach((w, i) => { if (!refPositions[w]) refPositions[w] = []; refPositions[w].push(i); });
  const matchedPositions = [];
  const usedPositions = new Set();
  const matchPairs = [];
  candTokens.forEach((word, ci) => {
    if (refPositions[word]) {
      for (const pos of refPositions[word]) {
        if (!usedPositions.has(pos)) {
          matchedPositions.push(pos);
          usedPositions.add(pos);
          matchPairs.push([ci, pos]);
          break;
        }
      }
    }
  });
  let numChunks = matchedPositions.length > 0 ? 1 : 0;
  const chunkIds = matchedPositions.length > 0 ? [0] : [];
  let currentChunk = 0;
  for (let i = 1; i < matchedPositions.length; i++) {
    if (matchedPositions[i] !== matchedPositions[i - 1] + 1) currentChunk++;
    chunkIds.push(currentChunk);
    if (matchedPositions[i] !== matchedPositions[i - 1] + 1) numChunks++;
  }
  const penalty = GAMMA * Math.pow(numChunks / numMatches, BETA);
  const score = Math.round(fmean * (1 - penalty) * 1000) / 1000;
  return { refTokens, candTokens, numMatches, precision, recall, fmean, numChunks, penalty, score, matchPairs, chunkIds, matchedPositions };
}

const stepInfo = [
  { title: 'Match Words', desc: 'Find exact unigram matches between reference and candidate (case-insensitive).', color: theme.colors.blue },
  { title: 'Precision & Recall', desc: 'P = matches/candidate_len, R = matches/ref_len. Alpha=0.9 weights recall higher.', color: theme.colors.yellow },
  { title: 'Chunks & Penalty', desc: 'Contiguous matched sequences form chunks. More chunks = worse word order = higher penalty.', color: theme.colors.pink },
  { title: 'METEOR Score', desc: 'Final score = F-mean x (1 - penalty). Good matches + good order = high score!', color: theme.colors.green },
];

export default function App() {
  const [candidate, setCandidate] = useState('The cat sat on the mat');
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);

  const result = useMemo(() => computeMeteor(REFERENCE, candidate), [candidate]);

  useEffect(() => {
    if (!playing) return;
    const timer = setTimeout(() => {
      if (step < 3) setStep(s => s + 1);
      else setPlaying(false);
    }, 1800);
    return () => clearTimeout(timer);
  }, [playing, step]);

  const handlePlay = () => {
    if (step >= 3) { setStep(0); setTimeout(() => setPlaying(true), 100); }
    else setPlaying(true);
  };
  const handleReset = () => { setPlaying(false); setStep(0); };

  const svgW = 560, svgH = 170;
  const refLen = result.refTokens.length || 1;
  const candLen = result.candTokens.length || 1;
  const maxLen = Math.max(refLen, candLen, 1);
  const slotW = Math.min(82, (svgW - 30) / maxLen);
  const refStartX = (svgW - refLen * slotW) / 2;
  const candStartX = (svgW - candLen * slotW) / 2;
  const refY = 35, candY = 140;

  const matchedRefSet = new Set(result.matchPairs.map(p => p[1]));
  const matchedCandSet = new Set(result.matchPairs.map(p => p[0]));

  const getChunkColor = (pairIdx) => {
    if (pairIdx < 0 || pairIdx >= result.chunkIds.length) return theme.colors.blue;
    return chunkColors[result.chunkIds[pairIdx] % chunkColors.length];
  };

  const getRefChunkColor = (refIdx) => {
    const pi = result.matchPairs.findIndex(p => p[1] === refIdx);
    if (pi < 0) return null;
    const mpIdx = result.matchPairs.slice(0, pi + 1).filter(p => result.matchPairs.indexOf(p) <= pi).length - 1;
    for (let i = 0; i < result.matchPairs.length; i++) {
      if (result.matchPairs[i][1] === refIdx) return getChunkColor(i);
    }
    return theme.colors.blue;
  };

  const getCandChunkColor = (candIdx) => {
    for (let i = 0; i < result.matchPairs.length; i++) {
      if (result.matchPairs[i][0] === candIdx) return getChunkColor(i);
    }
    return theme.colors.blue;
  };

  const showMatches = step >= 0;
  const showPR = step >= 1;
  const showChunks = step >= 2;
  const showFinal = step >= 3;

  const insight = useMemo(() => {
    if (result.numMatches === 0) return 'No matching words found. Try using some words from the reference!';
    if (result.score === 1) return 'Perfect score! All words match and are in the exact same order.';
    if (result.score >= 0.9) return 'Excellent! Nearly perfect match with good word ordering.';
    if (result.numMatches === Math.max(refLen, candLen) && result.numChunks > 1)
      return 'All words match, but scrambled order creates ' + result.numChunks + ' chunks -- the penalty drops the score significantly!';
    if (result.penalty > 0.3) return 'High fragmentation penalty! The matched words are scattered across ' + result.numChunks + ' chunks.';
    if (result.recall < 0.5) return 'Low recall: only ' + result.numMatches + ' of ' + refLen + ' reference words found in candidate.';
    if (result.precision < 0.5) return 'Low precision: many candidate words don\'t appear in the reference.';
    return result.numMatches + ' matches forming ' + result.numChunks + ' chunk' + (result.numChunks !== 1 ? 's' : '') + '. Penalty reduces F-mean from ' + result.fmean.toFixed(3) + ' to ' + result.score + '.';
  }, [result, refLen]);

  return (
    <div style={{ maxWidth: 600, margin: '0 auto', padding: '16px 12px', fontFamily: theme.font, background: theme.colors.background, color: theme.colors.text, minHeight: '100vh', boxSizing: 'border-box' }}>
      {/* Header */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 12 }}>
        <div>
          <div style={{ fontSize: 17, fontWeight: 700, color: theme.colors.text }}>METEOR Score</div>
          <div style={{ fontSize: 11, color: theme.colors.textMuted }}>Translation quality via matching + word order</div>
        </div>
        <div style={{ display: 'flex', gap: 6 }}>
          <button onClick={handlePlay} style={{ background: theme.colors.primary, color: '#fff', border: 'none', borderRadius: 6, padding: '5px 12px', fontSize: 12, cursor: 'pointer', fontFamily: theme.font, fontWeight: 600 }}>
            {playing ? 'Playing...' : 'Play'}
          </button>
          <button onClick={handleReset} style={{ background: theme.colors.surfaceAlt, color: theme.colors.textSecondary, border: '1px solid ' + theme.colors.border, borderRadius: 6, padding: '5px 10px', fontSize: 12, cursor: 'pointer', fontFamily: theme.font }}>Reset</button>
        </div>
      </div>

      {/* Reference */}
      <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 3, textTransform: 'uppercase', letterSpacing: 1 }}>Reference Translation</div>
      <div style={{ background: theme.colors.surface, border: '1px solid ' + theme.colors.border, borderRadius: 8, padding: '8px 12px', fontSize: 13, color: theme.colors.textSecondary, marginBottom: 10 }}>
        {REFERENCE}
      </div>

      {/* Candidate input */}
      <div style={{ fontSize: 10, color: theme.colors.textMuted, marginBottom: 3, textTransform: 'uppercase', letterSpacing: 1 }}>Candidate Translation (edit me!)</div>
      <input
        value={candidate}
        onChange={e => { setCandidate(e.target.value); setStep(0); setPlaying(false); }}
        style={{ width: '100%', background: theme.colors.surfaceAlt, border: '2px solid ' + theme.colors.primary, borderRadius: 8, padding: '8px 12px', fontSize: 13, color: theme.colors.text, fontFamily: theme.font, outline: 'none', boxSizing: 'border-box', marginBottom: 8 }}
      />

      {/* Presets */}
      <div style={{ display: 'flex', gap: 5, marginBottom: 14, flexWrap: 'wrap' }}>
        {presets.map(p => (
          <button key={p.label} onClick={() => { setCandidate(p.text); setStep(0); setPlaying(false); }}
            style={{ background: candidate === p.text ? theme.colors.primary + '33' : theme.colors.surface, color: candidate === p.text ? theme.colors.primary : theme.colors.textMuted, border: '1px solid ' + (candidate === p.text ? theme.colors.primary : theme.colors.border), borderRadius: 6, padding: '3px 9px', fontSize: 10, cursor: 'pointer', fontFamily: theme.font, transition: 'all 0.2s' }}>
            {p.label}
          </button>
        ))}
      </div>

      {/* SVG Matching Visualization */}
      <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '8px 4px', marginBottom: 12, border: '1px solid ' + theme.colors.border }}>
        <svg width="100%" viewBox={`0 0 ${svgW} ${svgH}`} style={{ display: 'block' }}>
          {/* Reference label */}
          <text x={10} y={refY - 14} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>REF</text>
          {/* Candidate label */}
          <text x={10} y={candY - 14} fontSize={9} fill={theme.colors.textMuted} fontFamily={theme.font}>CAND</text>

          {/* Reference word boxes */}
          {result.refTokens.map((word, i) => {
            const x = refStartX + i * slotW;
            const matched = matchedRefSet.has(i);
            const cc = showChunks && matched ? getRefChunkColor(i) : (showMatches && matched ? theme.colors.blue : theme.colors.textMuted);
            const bg = showMatches && matched ? cc + '22' : 'transparent';
            const borderC = showMatches && matched ? cc : theme.colors.border;
            return (
              <g key={'r' + i}>
                <rect x={x + 2} y={refY - 10} width={slotW - 4} height={24} rx={5} fill={bg} stroke={borderC} strokeWidth={matched && showMatches ? 1.5 : 0.5} style={{ transition: 'all 0.4s' }} />
                <text x={x + slotW / 2} y={refY + 5} textAnchor="middle" fontSize={11} fill={showMatches && matched ? cc : theme.colors.textMuted} fontFamily={theme.font} fontWeight={matched && showMatches ? 600 : 400} style={{ transition: 'all 0.4s' }}>
                  {word}
                </text>
              </g>
            );
          })}

          {/* Candidate word boxes */}
          {result.candTokens.map((word, i) => {
            const x = candStartX + i * slotW;
            const matched = matchedCandSet.has(i);
            const cc = showChunks && matched ? getCandChunkColor(i) : (showMatches && matched ? theme.colors.blue : theme.colors.textMuted);
            const bg = showMatches && matched ? cc + '22' : 'transparent';
            const borderC = showMatches && matched ? cc : theme.colors.border;
            return (
              <g key={'c' + i}>
                <rect x={x + 2} y={candY - 10} width={slotW - 4} height={24} rx={5} fill={bg} stroke={borderC} strokeWidth={matched && showMatches ? 1.5 : 0.5} style={{ transition: 'all 0.4s' }} />
                <text x={x + slotW / 2} y={candY + 5} textAnchor="middle" fontSize={11} fill={showMatches && matched ? cc : theme.colors.textMuted} fontFamily={theme.font} fontWeight={matched && showMatches ? 600 : 400} style={{ transition: 'all 0.4s' }}>
                  {word}
                </text>
              </g>
            );
          })}

          {/* Connection arcs */}
          {showMatches && result.matchPairs.map(([ci, ri], idx) => {
            const x1 = candStartX + ci * slotW + slotW / 2;
            const y1 = candY - 12;
            const x2 = refStartX + ri * slotW + slotW / 2;
            const y2 = refY + 16;
            const midY = (y1 + y2) / 2 + Math.abs(x1 - x2) * 0.08;
            const cc = showChunks ? getChunkColor(idx) : theme.colors.blue;
            return (
              <path key={'arc' + idx}
                d={`M ${x1} ${y1} Q ${(x1 + x2) / 2} ${midY} ${x2} ${y2}`}
                fill="none" stroke={cc} strokeWidth={showChunks ? 2 : 1.2}
                strokeDasharray={showChunks ? 'none' : '4,3'}
                opacity={showMatches ? 0.7 : 0}
                style={{ transition: 'all 0.5s' }}
              />
            );
          })}

          {/* Chunk labels */}
          {showChunks && result.numChunks > 0 && (() => {
            const labels = [];
            let chunkStart = 0;
            for (let i = 0; i <= result.chunkIds.length; i++) {
              if (i === result.chunkIds.length || (i > 0 && result.chunkIds[i] !== result.chunkIds[i - 1])) {
                const startRI = result.matchPairs[chunkStart][1];
                const endRI = result.matchPairs[i - 1][1];
                const cx = refStartX + ((startRI + endRI) / 2) * slotW + slotW / 2;
                const col = chunkColors[result.chunkIds[chunkStart] % chunkColors.length];
                labels.push(
                  <text key={'ch' + chunkStart} x={cx} y={refY + 30} textAnchor="middle" fontSize={8} fill={col} fontFamily={theme.font} fontWeight={600} opacity={0.8}>
                    chunk {result.chunkIds[chunkStart] + 1}
                  </text>
                );
                chunkStart = i;
              }
            }
            return labels;
          })()}
        </svg>
      </div>

      {/* Step controls */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 10, marginBottom: 12 }}>
        <button onClick={() => { setStep(Math.max(0, step - 1)); setPlaying(false); }} disabled={step === 0}
          style={{ background: 'none', border: '1px solid ' + theme.colors.border, color: step === 0 ? theme.colors.textMuted : theme.colors.text, borderRadius: 6, padding: '3px 10px', cursor: step === 0 ? 'default' : 'pointer', fontFamily: theme.font, fontSize: 13 }}>{'<'}</button>
        <div style={{ fontSize: 11, color: stepInfo[step].color, fontWeight: 600, minWidth: 140, textAlign: 'center' }}>
          Step {step + 1}/4: {stepInfo[step].title}
        </div>
        <button onClick={() => { setStep(Math.min(3, step + 1)); setPlaying(false); }} disabled={step === 3}
          style={{ background: 'none', border: '1px solid ' + theme.colors.border, color: step === 3 ? theme.colors.textMuted : theme.colors.text, borderRadius: 6, padding: '3px 10px', cursor: step === 3 ? 'default' : 'pointer', fontFamily: theme.font, fontSize: 13 }}>{'>'}</button>
      </div>

      {/* Computation display */}
      <div style={{ background: theme.colors.surface, borderRadius: 10, padding: 14, marginBottom: 10, border: '1px solid ' + theme.colors.border }}>
        {/* Matches */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: showPR ? 10 : 0 }}>
          <span style={{ fontSize: 11, color: theme.colors.textSecondary }}>Matches</span>
          <span style={{ fontSize: 14, fontWeight: 700, color: theme.colors.blue }}>
            {result.numMatches} / {Math.max(refLen, candLen)} words
          </span>
        </div>

        {/* Precision & Recall */}
        {showPR && (
          <div style={{ marginBottom: showChunks ? 10 : 0 }}>
            <div style={{ display: 'flex', gap: 12, marginBottom: 6 }}>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.colors.textMuted, marginBottom: 3 }}>
                  <span>Precision (M/Cand)</span>
                  <span style={{ color: theme.colors.yellow }}>{result.precision.toFixed(3)}</span>
                </div>
                <div style={{ height: 6, background: theme.colors.surfaceAlt, borderRadius: 3, overflow: 'hidden' }}>
                  <div style={{ height: '100%', width: (result.precision * 100) + '%', background: theme.colors.yellow, borderRadius: 3, transition: 'width 0.5s' }} />
                </div>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.colors.textMuted, marginBottom: 3 }}>
                  <span>Recall (M/Ref)</span>
                  <span style={{ color: theme.colors.orange }}>{result.recall.toFixed(3)}</span>
                </div>
                <div style={{ height: 6, background: theme.colors.surfaceAlt, borderRadius: 3, overflow: 'hidden' }}>
                  <div style={{ height: '100%', width: (result.recall * 100) + '%', background: theme.colors.orange, borderRadius: 3, transition: 'width 0.5s' }} />
                </div>
              </div>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 10, color: theme.colors.textMuted }}>
              <span>F-mean (alpha=0.9, favors recall)</span>
              <span style={{ color: theme.colors.yellow, fontWeight: 600 }}>{result.fmean.toFixed(3)}</span>
            </div>
          </div>
        )}

        {/* Chunks & Penalty */}
        {showChunks && (
          <div style={{ marginBottom: showFinal ? 10 : 0 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
              <span style={{ fontSize: 11, color: theme.colors.textSecondary }}>Chunks</span>
              <span style={{ fontSize: 14, fontWeight: 700, color: theme.colors.pink }}>
                {result.numChunks} chunk{result.numChunks !== 1 ? 's' : ''}
              </span>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 4 }}>
              <span style={{ fontSize: 10, color: theme.colors.textMuted }}>Penalty = 0.5 * ({result.numChunks}/{result.numMatches})^3</span>
              <span style={{ fontSize: 12, fontWeight: 600, color: result.penalty > 0.2 ? '#f43f5e' : theme.colors.pink }}>{result.penalty.toFixed(4)}</span>
            </div>
            <div style={{ height: 6, background: theme.colors.surfaceAlt, borderRadius: 3, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: Math.min(result.penalty * 100 * 2, 100) + '%', background: result.penalty > 0.2 ? '#f43f5e' : theme.colors.pink, borderRadius: 3, transition: 'width 0.5s' }} />
            </div>
          </div>
        )}

        {/* Final Score */}
        {showFinal && (
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 6 }}>
              <span style={{ fontSize: 12, color: theme.colors.text, fontWeight: 600 }}>METEOR = F-mean * (1 - penalty)</span>
              <span style={{ fontSize: 20, fontWeight: 800, color: result.score >= 0.7 ? theme.colors.green : result.score >= 0.4 ? theme.colors.yellow : '#f43f5e' }}>
                {result.score.toFixed(3)}
              </span>
            </div>
            <div style={{ height: 8, background: theme.colors.surfaceAlt, borderRadius: 4, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: (result.score * 100) + '%', background: result.score >= 0.7 ? theme.colors.green : result.score >= 0.4 ? theme.colors.yellow : '#f43f5e', borderRadius: 4, transition: 'width 0.5s' }} />
            </div>
            <div style={{ fontSize: 10, color: theme.colors.textMuted, marginTop: 4, textAlign: 'center' }}>
              {result.fmean.toFixed(3)} * (1 - {result.penalty.toFixed(4)}) = {result.score.toFixed(3)}
            </div>
          </div>
        )}
      </div>

      {/* Step description + insight */}
      <div style={{ background: theme.colors.surfaceAlt, borderRadius: 8, padding: '10px 14px', fontSize: 11, color: theme.colors.textSecondary, borderLeft: '3px solid ' + stepInfo[step].color }}>
        <div style={{ marginBottom: 4, fontSize: 10, color: stepInfo[step].color, fontWeight: 600 }}>{stepInfo[step].desc}</div>
        <div style={{ fontSize: 10, color: theme.colors.textMuted, fontStyle: 'italic' }}>{insight}</div>
      </div>
    </div>
  );
}
